import { db } from '@mindstudio-ai/agent';

/**
 * A GitHub repository the user has added to the system.
 *
 * System columns (`id`, `created_at`, `updated_at`, `last_updated_by`) are
 * provided automatically by the platform and must not be redeclared here.
 */
interface Repository {
  // Full HTTPS URL to the repo, e.g. "https://github.com/owner/name".
  // Logical unique key for the table.
  githubUrl: string;

  // Display name, typically derived from the URL ("owner/name").
  // Stored separately so the UI does not re-parse on every render.
  repoName: string;

  // Unix-ms timestamp of the most recent successful ingestion run.
  // `undefined` until the first scan completes; updated on every re-scan.
  // Distinct from the auto-managed `updated_at`, which moves on any write.
  lastScannedAt?: number;
}

export const Repositories = db.defineTable<Repository>('repositories', {
  // Required so re-ingestion of an already-known repo can `upsert` on URL
  // instead of creating a duplicate row.
  unique: [['githubUrl']],
});

import { db } from '@mindstudio-ai/agent';

/**
 * A single source file discovered inside a repository during ingestion.
 * Owned by exactly one repository.
 *
 * The interface is named `RepoFile` rather than `File` to avoid colliding
 * with the global DOM `File` type. The exported table is still `Files`.
 *
 * System columns (`id`, `created_at`, `updated_at`, `last_updated_by`) are
 * provided automatically by the platform and must not be redeclared here.
 */
interface RepoFile {
  // FK -> repositories.id. Cascading delete enforced in application code.
  repoId: string;

  // Path relative to the repo root, e.g. "src/lib/auth.ts".
  // Always stored with forward slashes regardless of source OS.
  filePath: string;

  // Detected language label, e.g. "typescript", "python", "go", "markdown",
  // "unknown". Free-form string in this step; vocabulary may be tightened
  // later without a schema change.
  language: string;
}

export const Files = db.defineTable<RepoFile>('files', {
  // A given path appears at most once per repo. Lets re-ingestion `upsert`
  // on (repoId, filePath) rather than duplicate rows.
  unique: [['repoId', 'filePath']],
});

import { db } from '@mindstudio-ai/agent';

/**
 * A semantic unit extracted from a file by the AST parser. A single file
 * produces many chunks. Each chunk carries its source text, a coarse type
 * label, and an embedding vector for retrieval.
 *
 * System columns (`id`, `created_at`, `updated_at`, `last_updated_by`) are
 * provided automatically by the platform and must not be redeclared here.
 */
interface CodeChunk {
  // FK -> files.id. Cascading delete enforced in application code.
  fileId: string;

  // The exact source text of the chunk, preserved verbatim (whitespace and
  // all) so retrieval results can be shown to the user as-is.
  chunkText: string;

  // Coarse category produced by the AST parser. Initial vocabulary:
  // "function" | "class" | "method" | "interface" | "type" | "import"
  // | "boilerplate" | "comment" | "other". Free-form at the column level;
  // the parser is responsible for staying within the agreed set.
  chunkType: string;

  // Embedding vector, stored as a JSON array of floats. Length is whatever
  // the embedding model produces (e.g. 1536 for text-embedding-3-small);
  // not constrained at the schema level, so the model can be swapped
  // without a migration. Cosine similarity is computed in-process by
  // methods at query time for the MVP.
  embedding: number[];
}

// No unique constraint: a file can produce many chunks, and identical
// chunk text can legitimately recur (boilerplate, repeated imports).
// De-duplication, if desired, is a pipeline concern, not a schema rule.
export const CodeChunks = db.defineTable<CodeChunk>('code_chunks');

import { db } from '@mindstudio-ai/agent';

/**
 * Markdown documentation produced by the AI agents for a given file.
 * Multiple rows per file are intentional so the history of generated docs
 * is preserved across re-runs of the agents.
 *
 * Note: `createdAt` is intentionally NOT redeclared. The platform provides
 * a system `created_at` column on every row (unix ms) which serves the
 * "generated on ..." UI value. Adding a separate `createdAt` would create
 * a confusing duplicate. Read `doc.created_at` directly.
 *
 * System columns (`id`, `created_at`, `updated_at`, `last_updated_by`) are
 * provided automatically by the platform and must not be redeclared here.
 */
interface GeneratedDoc {
  // FK -> files.id. Cascading delete enforced in application code.
  fileId: string;

  // The full markdown body produced by the Deep-Dive agent (or, in some
  // flows, the Mapper). May embed Mermaid flowchart blocks; rendering is
  // a frontend concern. Stored as-is.
  markdownContent: string;
}

// No unique constraint: multiple generations per file are valid and
// intentional. Re-running the agents must not destroy previous output.
// "Latest doc for a file" is a query
// (`sortBy(d => d.created_at).reverse().take(1)`), not a uniqueness rule.
export const GeneratedDocs = db.defineTable<GeneratedDoc>('generated_docs');

