async function analyzeFile(
  filePath: string,
  fileContent: string,
  architectureSummary: string,
): Promise<{ filePath: string; writeup: string }> {
  const { content } = await mindstudio.generateText(
    {
      message: `<architecture_context>
${architectureSummary}
</architecture_context>

<file_path>${filePath}</file_path>

<source_code>
${fileContent}
</source_code>`,
      modelOverride: {
        model: MODEL_ID,
        temperature: 0,             // factual extraction — fully deterministic
        maxResponseTokens: 16000,   // do not reduce — reasoning tokens count against this; per-file output can reach 8K tokens
        // reasoning intentionally omitted (defaults false on 4.6):
        // 200 calls × reasoning overhead = unacceptable latency + cost.
        // Adaptive thinking still fires on complex files; default-off is correct here.
        preamble: FILE_ANALYSIS_PREAMBLE,
      },
      chatHistoryMode: 'exclude', // critical: each file must be fully isolated, no history bleed
    },
  );

  return { filePath, writeup: content };
}

// ─── CONCURRENCY-CONTROLLED LOOP ────────────────────────────────────────────
// DO NOT run 200 calls sequentially (hours of wall time).
// DO NOT Promise.all 200 at once (hammers rate limits).
// Use a concurrency pool. 8 is a safe default; tune up if your account allows.

async function analyzeAllFiles(
  files: { path: string; content: string }[],
  architectureSummary: string,
  concurrency = 8,  // tune based on your account's rate limit headroom
): Promise<{ filePath: string; writeup: string }[]> {
  const results: { filePath: string; writeup: string }[] = [];
  const errors: { filePath: string; error: string }[] = [];
  const queue = [...files];
  let inFlight = 0;
  let completed = 0;

  await new Promise<void>((resolve, reject) => {
    function dispatch() {
      while (inFlight < concurrency && queue.length > 0) {
        const file = queue.shift()!;
        inFlight++;

        analyzeFile(file.path, file.content, architectureSummary)
          .then((result) => {
            results.push(result);
          })
          .catch((err) => {
            // SDK already retried 429s. If we're here, it's a hard failure.
            const msg = err instanceof MindStudioError
              ? `${err.code} (HTTP ${err.status}): ${err.message}`
              : String(err);
            errors.push({ filePath: file.path, error: msg });
            console.error(`Failed: ${file.path} — ${msg}`);
          })
          .finally(() => {
            inFlight--;
            completed++;
            console.log(`[${completed}/${files.length}] ${file.path}`);

            if (queue.length === 0 && inFlight === 0) {
              resolve();
            } else {
              dispatch();
            }
          });
      }
    }
    dispatch();
  });

  if (errors.length > 0) {
    // Return partial results — don't fail the whole job over a few bad files
    console.warn(`${errors.length}/${files.length} files failed. Returning partial results.`);
  }

  return results;
}

// ─── MAIN ENTRYPOINT ────────────────────────────────────────────────────────

export async function analyzeCodebase(input: {
  fileTree: string;
  files: { path: string; content: string }[];
}): Promise<{
  architectureSummary: string;
  fileWriteups: { filePath: string; writeup: string }[];
}> {
  // Step 1: Architecture summary (one call, reasoning enabled)
  console.log('Generating architecture summary...');
  const architectureSummary = await generateArchitectureSummary(input.fileTree);

  // Step 2: Per-file analysis (concurrency-controlled, reasoning disabled)
  console.log(`Analyzing ${input.files.length} files with concurrency=8...`);
  const fileWriteups = await analyzeAllFiles(input.files, architectureSummary);

  return { architectureSummary, fileWriteups };
}
```

---

## Key Decisions Summary

| Decision | Why |
|---|---|
| `claude-4-6-sonnet` for both tasks | 128K response cap (reasoning tokens eat into this on 4.5); adaptive thinking; popularity 1.0 |
| Reasoning ON for Step 1, OFF for Step 2 | Architecture synthesis benefits from extended thinking; per-file is pattern-matching, not reasoning |
| `temperature: 0` for file analysis | Deterministic extraction. Variance is a bug here |
| `temperature: 0.1` for architecture summary | Synthesis needs to connect dots across the tree — slight latitude is correct |
| `chatHistoryMode: 'exclude'` on all calls | Prevent any thread-level context bleeding between file analyses |
| `preamble` for system instructions | Correct separation of system vs. user content; maps to the model's system prompt slot |
| Concurrency pool at 8, not `executeStepBatch` | Batch is capped at 50 and would send massive payloads; pool gives you tunable throughput and per-file error isolation |
| Partial failure handling (not hard throw) | A 200-file background job should not fail entirely because 2 files hit a transient error |

