+/*
+ * Codebase Bible — design tokens.
+ * Dark, IDE-inspired. Single accent (mint/cyan). Inter for prose,
+ * JetBrains Mono for code. Sharp 1px lines, no rounded corners on chrome.
+ */
+
+:root {
+  /* Surfaces */
+  --bg: #0a0b0d;
+  --bg-elevated: #111316;
+  --bg-pane: #0d0f12;
+  --bg-hover: #1a1d22;
+  --bg-active: #232830;
+
+  /* Borders */
+  --border: #1f242b;
+  --border-strong: #2c333d;
+
+  /* Text */
+  --text: #e8eaed;
+  --text-secondary: #9aa0a6;
+  --text-muted: #5f6368;
+
+  /* Accent */
+  --accent: #00d4a4;
+  --accent-dim: #00aa84;
+  --accent-fade: rgba(0, 212, 164, 0.1);
+
+  /* States */
+  --status-processing: #f59e0b;
+  --status-completed: #00d4a4;
+  --status-failed: #ef4444;
+  --status-idle: #6b7280;
+
+  /* Typography */
+  --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
+  --font-mono: 'JetBrains Mono', ui-monospace, 'SF Mono', Menlo, monospace;
+
+  /* Spacing scale */
+  --sp-1: 4px;
