+  background: var(--border-strong);
+}
+
+/* ───────── Buttons ───────── */
+
+button {
+  font-family: inherit;
+  font-size: inherit;
+}
+
+.btn {
+  display: inline-flex;
+  align-items: center;
+  justify-content: center;
