+  font-size: 13px;
+  line-height: 1.5;
+  z-index: 1000;
+  animation: slideIn 200ms ease-out;
+}
+.toast.is-error {
+  border-left: 3px solid var(--status-failed);
+}
+.toast.is-success {
+  border-left: 3px solid var(--status-completed);
+}
+@keyframes slideIn {
+  from {
+    transform: translateX(20px);
+    opacity: 0;
+  }
+  to {
+    transform: translateX(0);
+    opacity: 1;
+  }
+}
+
+/* ───────── Highlight.js theme override (atom-one-dark-ish) ───────── */
+
+.hljs {
+  background: var(--bg-pane);
+  color: #d4d4d4;
+}
+.hljs-comment,
+.hljs-quote {
+  color: #6b7280;
+  font-style: italic;
+}
+.hljs-keyword,
+.hljs-selector-tag,
+.hljs-built_in,
+.hljs-name,
+.hljs-tag {
+  color: #c678dd;
+}
+.hljs-string,
+.hljs-title,
+.hljs-section,
+.hljs-attribute,
+.hljs-literal,
+.hljs-template-tag,
+.hljs-template-variable,
+.hljs-type,
+.hljs-addition {
+  color: #98c379;
+}
+.hljs-number,
+.hljs-symbol,
+.hljs-bullet,
+.hljs-meta,
+.hljs-link {
+  color: #d19a66;
+}
+.hljs-variable,
+.hljs-regexp {
+  color: #e06c75;
+}
+.hljs-doctag,
+.hljs-strong {
+  font-weight: 700;
+}
+.hljs-emphasis {
+  font-style: italic;
+}
+.hljs-function .hljs-title,
+.hljs-title.function_ {
+  color: #61afef;
+}
+.hljs-params {
+  color: #d4d4d4;
 }

