+
+// ─── Toolbar ────────────────────────────────────────────────────────
+
+function Toolbar({
+  detail,
+  repositoryId,
+  onPrCreated,
+  onPrError,
+}: {
+  detail: RepositoryDetail;
+  repositoryId: string;
+  onPrCreated: (url: string, number: number) => void;
+  onPrError: (message: string) => void;
+}) {
+  const [pushing, setPushing] = useState(false);
+  const [regenerating, setRegenerating] = useState(false);
+
+  const handlePush = async () => {
+    if (pushing) return;
+    setPushing(true);
+    try {
+      const res = await api.openDocumentationPR({ repositoryId });
+      onPrCreated(res.prUrl, res.prNumber);
+    } catch (err: unknown) {
+      const message = err instanceof Error ? err.message : String(err);
+      onPrError(message);
+    } finally {
+      setPushing(false);
+    }
+  };
+
+  const handleRegenerate = async () => {
+    if (regenerating) return;
+    setRegenerating(true);
+    try {
+      await api.generateBible({ repositoryId });
+    } catch (err: unknown) {
+      const message = err instanceof Error ? err.message : String(err);
+      onPrError(message);
+    } finally {
+      // Polling in the parent will pick up docsStatus='generating' and
+      // route us back to the loading view automatically.
+      setRegenerating(false);
+    }
+  };
+
+  return (
+    <div
+      style={{
+        gridArea: 'toolbar',
+        display: 'flex',
+        alignItems: 'center',
+        justifyContent: 'space-between',
+        padding: '0 24px',
+        borderBottom: '1px solid var(--border)',
+        background: 'var(--bg-elevated)',
+        userSelect: 'none',
+      }}
+    >
+      <div style={{ display: 'flex', alignItems: 'center', gap: 16, minWidth: 0 }}>
+        <Link
+          href="/"
+          style={{
+            color: 'var(--text-muted)',
+            fontFamily: 'var(--font-mono)',
+            fontSize: 12,
+            textDecoration: 'none',
+          }}
+        >
+          ← all repos
+        </Link>
+        <div
+          style={{
+            width: 1,
+            height: 24,
+            background: 'var(--border)',
+          }}
+        />
+        <div
+          style={{
+            fontFamily: 'var(--font-mono)',
+            fontSize: 14,
+            fontWeight: 600,
+            color: 'var(--text)',
+            overflow: 'hidden',
