+}
+
+// ─── Sidebar (file tree) ────────────────────────────────────────────
+
+type View = { kind: 'overview' } | { kind: 'file'; fileId: string };
+
+function Sidebar({
+  detail,
+  view,
+  onSelectOverview,
+  onSelectFile,
+}: {
+  detail: RepositoryDetail;
+  view: View;
+  onSelectOverview: () => void;
+  onSelectFile: (f: FileSummary) => void;
+  selectedFileId: string | null;
+}) {
+  return (
+    <aside
+      style={{
+        gridArea: 'sidebar',
+        borderRight: '1px solid var(--border)',
+        background: 'var(--bg-pane)',
+        overflowY: 'auto',
+        padding: '16px 0',
+      }}
+    >
+      <div style={{ padding: '0 16px 12px', userSelect: 'none' }}>
+        <div
+          style={{
+            fontFamily: 'var(--font-mono)',
+            fontSize: 10,
+            textTransform: 'uppercase',
+            letterSpacing: '0.12em',
+            color: 'var(--text-muted)',
+            marginBottom: 6,
+          }}
+        >
+          Overview
+        </div>
+        <FileRow
+          label="Architecture"
+          subtitle={detail.overview ? 'Mermaid + summary' : 'Not generated'}
+          active={view.kind === 'overview'}
+          disabled={!detail.overview}
+          onClick={onSelectOverview}
+        />
+      </div>
+      <div style={{ padding: '0 16px' }}>
+        <div
+          style={{
+            fontFamily: 'var(--font-mono)',
+            fontSize: 10,
+            textTransform: 'uppercase',
+            letterSpacing: '0.12em',
+            color: 'var(--text-muted)',
