+            display: 'flex',
+            justifyContent: 'space-between',
+          }}
+        >
+          <span>Files</span>
+          <span>{detail.files.length}</span>
+        </div>
+        <div style={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
+          {detail.files.map((f) => {
+            const active = view.kind === 'file' && view.fileId === f.id;
+            return (
+              <FileRow
+                key={f.id}
+                label={f.filePath}
+                subtitle={f.language}
+                active={active}
+                disabled={!f.hasDoc}
+                onClick={() => f.hasDoc && onSelectFile(f)}
+              />
+            );
+          })}
+        </div>
+      </div>
+    </aside>
+  );
