+// ─── Reader ─────────────────────────────────────────────────────────
+
+function Reader({ detail, view }: { detail: RepositoryDetail; view: View }) {
+  const content = (() => {
+    if (view.kind === 'overview') return detail.overview?.markdownContent ?? '';
+    const doc = detail.fileDocsByFileId[view.fileId];
+    return doc?.markdownContent ?? '';
