+        <div
+          style={{
+            fontFamily: 'var(--font-mono)',
+            fontSize: 11,
+            textTransform: 'uppercase',
+            letterSpacing: '0.08em',
+            color: 'var(--text-muted)',
+            marginBottom: 16,
+          }}
+        >
+          {meta}
+        </div>
+      )}
+      {content ? (
+        <MarkdownView content={content} />
+      ) : (
+        <div
+          style={{
+            color: 'var(--text-muted)',
+            fontFamily: 'var(--font-mono)',
+            fontSize: 13,
+            padding: '64px 0',
+          }}
+        >
+          No documentation available for this selection.
+        </div>
+      )}
+    </section>
+  );
+}
+
+// ─── Full-screen status (loading / error / waiting) ────────────────
+
+function FullScreenStatus({
+  title,
+  subtitle,
+  showHome,
+  showSecondary,
+  secondaryLabel,
+  onSecondary,
+  progressFiles,
+}: {
+  title: string;
+  subtitle: string | null;
+  showHome?: boolean;
+  showSecondary?: boolean;
+  secondaryLabel?: string;
+  onSecondary?: () => void | Promise<void>;
+  progressFiles?: number;
+}) {
+  return (
+    <div
+      style={{
+        flex: 1,
+        display: 'flex',
+        alignItems: 'center',
+        justifyContent: 'center',
+        padding: 24,
+      }}
+    >
+      <div style={{ maxWidth: 520, textAlign: 'center' }}>
+        <div
+          style={{
+            fontFamily: 'var(--font-mono)',
+            fontSize: 11,
+            textTransform: 'uppercase',
+            letterSpacing: '0.12em',
+            color: 'var(--accent)',
+            marginBottom: 12,
+          }}
+        >
+          Codebase Bible
+        </div>
+        <h1
+          style={{
+            fontSize: 28,
+            fontWeight: 700,
+            letterSpacing: '-0.02em',
+            margin: 0,
+          }}
+        >
+          {title}
+        </h1>
+        {subtitle && (
+          <p
+            style={{
+              marginTop: 12,
+              color: 'var(--text-secondary)',
+              fontSize: 14,
+              lineHeight: 1.55,
+            }}
+          >
+            {subtitle}
+          </p>
+        )}
+        {typeof progressFiles === 'number' && progressFiles > 0 && (
+          <div
+            style={{
+              marginTop: 24,
+              fontFamily: 'var(--font-mono)',
+              fontSize: 12,
+              color: 'var(--text-muted)',
+            }}
+          >
+            {progressFiles} {progressFiles === 1 ? 'file' : 'files'} queued
+          </div>
+        )}
+        <div
+          style={{
+            marginTop: 32,
+            display: 'flex',
+            gap: 8,
+            justifyContent: 'center',
+          }}
+        >
+          {showHome && (
+            <Link
+              href="/"
+              style={{
+                color: 'var(--text)',
+                textDecoration: 'none',
+                fontFamily: 'var(--font-sans)',
+                fontSize: 13,
+                fontWeight: 500,
+              }}
+              className="btn"
+            >
+              Back home
+            </Link>
+          )}
+          {showSecondary && secondaryLabel && onSecondary && (
+            <button
+              className="btn btn-primary"
+              onClick={() => {
+                void onSecondary();
+              }}
+            >
+              {secondaryLabel}
+            </button>
+          )}
+        </div>
+      </div>
+    </div>
+  );
+}
+
+function formatRelative(unixMs: number): string {
+  const diffMs = Date.now() - unixMs;
+  const sec = Math.round(diffMs / 1000);
+  if (sec < 60) return `${sec}s ago`;
+  const min = Math.round(sec / 60);
+  if (min < 60) return `${min}m ago`;
+  const hr = Math.round(min / 60);
+  if (hr < 24) return `${hr}h ago`;
+  const day = Math.round(hr / 24);
+  return `${day}d ago`;
+}
