    <!-- LEFT BRAND ZONE -->
    <div class="brand">
      <div class="glyph">
        <!-- mint mark: vertical cursor + 3 horizontal lines (open codex glyph) -->
        <svg width="22" height="22" viewBox="0 0 22 22" fill="none">
          <line x1="11" y1="3" x2="11" y2="19" stroke="#00d4a4" stroke-width="2"/>
          <line x1="4"  y1="7"  x2="9"  y2="7"  stroke="#00d4a4" stroke-width="2"/>
          <line x1="13" y1="7"  x2="18" y2="7"  stroke="#00d4a4" stroke-width="2"/>
          <line x1="4"  y1="11" x2="9"  y2="11" stroke="#00d4a4" stroke-width="2"/>
          <line x1="13" y1="11" x2="18" y2="11" stroke="#00d4a4" stroke-width="2"/>
          <line x1="4"  y1="15" x2="9"  y2="15" stroke="#00d4a4" stroke-width="2"/>
          <line x1="13" y1="15" x2="18" y2="15" stroke="#00d4a4" stroke-width="2"/>
        </svg>
      </div>
      <div class="eyebrow">$ <span class="dim">bible</span> generate _</div>
      <div class="wordmark">codebase<br/><span class="l2">bible.</span></div>
      <div class="tagline">
        AI-generated technical documentation for any GitHub repository. <b>Shipped as a pull request.</b>
      </div>
      <div class="footer-meta">
        <span class="dot"></span>
        <span>v1.0</span>
        <span>·</span>
