      </div>
    </div>

    <!-- RIGHT IDE PROOF -->
    <div class="ide">
      <div class="ide-bar">
        <div class="left">
          <span class="crumb">vercel/next.js · <b>docs/auth.md</b></span>
        </div>
        <div class="right">
          <span class="pr-pill">PR ready</span>
        </div>
      </div>
      <div class="ide-body">
        <div class="tree">
          <div class="row dir"><span class="ic">▾</span>src</div>
          <div class="row indent"><span class="ic">▾</span>methods</div>
