  1 import { useEffect, useState, type FormEvent } from 'react';
  2 import { useLocation } from 'wouter';
  3 import { api, type RepoSummary } from '../api';
  4 
  5 /**
  6  * Home page. Two areas:
  7  *   - Top hero with the URL input.
  8  *   - Below: list of every repo the system already knows about, with
  9  *     status pills and quick links into each repo's dashboard.
 10  *
 11  * Submit flow:
 12  *   1. POST ingestRepository → repositoryId returned in <500ms.
 13  *   2. Navigate immediately to /repos/<id>. The dashboard handles the
 14  *      polling + auto-trigger for generateBible. We don't block the
 15  *      home page on async work.
 16  */
 17 export default function HomePage() {
 18   const [, navigate] = useLocation();
 19   const [url, setUrl] = useState('');
 20   const [submitting, setSubmitting] = useState(false);
 21   const [error, setError] = useState<string | null>(null);
 22 
 23   const [repos, setRepos] = useState<RepoSummary[] | null>(null);
 24   const [reposLoading, setReposLoading] = useState(true);
 25 
 26   // Initial load + refresh-on-mount. We poll lightly (every 5s) so any
 27   // repo that's currently processing/generating shows live status.
 28   useEffect(() => {
 29     let cancelled = false;
 30     let timer: ReturnType<typeof setTimeout> | null = null;
 31 
 32     const tick = async () => {
 33       try {
 34         const res = await api.listRepositories();
 35         if (!cancelled) {
 36           setRepos(res.repositories);
 37           setReposLoading(false);
 38         }
 39       } catch (err) {
 40         if (!cancelled) {
 41           console.error('listRepositories failed', err);
 42           setReposLoading(false);
 43         }
 44       }
 45       if (!cancelled) {
 46         timer = setTimeout(tick, 5000);
 47       }
 48     };
 49     tick();
 50 
 51     return () => {
 52       cancelled = true;
 53       if (timer) clearTimeout(timer);
 54     };
 55   }, []);
 56 
 57   const handleSubmit = async (e: FormEvent) => {
 58     e.preventDefault();
 59     if (!url.trim() || submitting) return;
 60     setError(null);
 61     setSubmitting(true);
 62     try {
 63       const res = await api.ingestRepository({ githubUrl: url.trim() });
 64       // Hand off to the dashboard, which will poll status and auto-trigger
 65       // generateBible once ingestion completes.
 66       navigate(`/repos/${res.repositoryId}?autogenerate=1`);
 67     } catch (err: unknown) {
 68       const message = err instanceof Error ? err.message : String(err);
 69       setError(message);
 70       setSubmitting(false);
 71     }
 72   };
 73 
 74   return (
 75     <div
 76       style={{
 77         flex: 1,
 78         display: 'flex',
 79         flexDirection: 'column',
 80         alignItems: 'center',
 81         padding: '64px 24px 80px',
 82       }}
 83     >
 84       <div style={{ width: '100%', maxWidth: 720 }}>
 85         <Hero />
 86         <form onSubmit={handleSubmit} style={{ marginTop: 32 }}>
 87           <div style={{ display: 'flex', gap: 8 }}>
 88             <input
 89               type="url"
 90               required
 91               autoFocus
 92               placeholder="https://github.com/owner/repo"
 93               value={url}
 94               onChange={(e) => setUrl(e.target.value)}
 95               disabled={submitting}
 96               className="input"
 97               style={{ flex: 1 }}
 98             />
 99             <button
100               type="submit"
101               disabled={submitting || !url.trim()}
102               className="btn btn-primary"
103               style={{ minWidth: 160 }}
104             >
105               {submitting ? <Spinner /> : 'Generate Bible →'}
106             </button>
107           </div>
108           {error && (
109             <div
110               style={{
111                 marginTop: 12,
112                 padding: '10px 14px',
113                 background: 'var(--bg-elevated)',
114                 borderLeft: '3px solid var(--status-failed)',
115                 fontFamily: 'var(--font-mono)',
116                 fontSize: 12,
117                 color: 'var(--text-secondary)',
118               }}
119             >
120               {error}
121             </div>
122           )}
123         </form>
124 
125         <div
126           style={{
127             marginTop: 16,
128             fontFamily: 'var(--font-mono)',
129             fontSize: 11,
130             color: 'var(--text-muted)',
131             letterSpacing: '0.02em',
132           }}
133         >
134           Public repos work without configuration. Private repos and PR creation require a GITHUB_TOKEN secret.
135         </div>
136 
137         <div style={{ marginTop: 64 }}>
138           <SectionLabel>Repositories</SectionLabel>
139           <RepoList repos={repos} loading={reposLoading} />
140         </div>
141       </div>
142     </div>
143   );
144 }
