   1 /**
   2  * Repository dashboard. Three states the page transitions through:
   3  *
   4  *   1. INGESTING   — `repo.status === 'processing'`. Polling.
   5  *                    On `'completed'`, if `?autogenerate=1` is in the URL
   6  *                    AND `docsStatus === 'idle'`, fire generateBible
   7  *                    automatically (then drop the query param).
   8  *
   9  *   2. GENERATING  — `repo.docsStatus === 'generating'`. Polling.
  10  *                    A skeleton tree + progress message.
  11  *
  12  *   3. READY       — both completed. Full dashboard: file tree (left),
  13  *                    markdown reader (right), "Push to GitHub" (top-right).
  14  *
  15  * Failures (`status === 'failed'` or `docsStatus === 'failed'`) surface
  16  * inline with a short message and a back-to-home link.
  17  */
  18 
  19 import { useEffect, useMemo, useState } from 'react';
  20 import { useLocation, useRoute, Link } from 'wouter';
  21 import { api, type RepositoryDetail, type FileSummary } from '../api';
  22 import MarkdownView from '../components/MarkdownView';
  23 
  24 const POLL_INTERVAL_MS = 3000;
  25 
  26 export default function RepoPage() {
  27   const [match, params] = useRoute<{ id: string }>('/repos/:id');
  28   const [location, navigate] = useLocation();
  29   const repositoryId = params?.id ?? '';
  30   const autogenerateRequested = useMemo(
  31     () => new URLSearchParams(location.split('?')[1] ?? '').get('autogenerate') === '1',
  32     [location],
  33   );
  34   const [autogenerateConsumed, setAutogenerateConsumed] = useState(false);
  35 
  36   const [detail, setDetail] = useState<RepositoryDetail | null>(null);
  37   const [pollError, setPollError] = useState<string | null>(null);
  38   const [selectedFileId, setSelectedFileId] = useState<string | null>(null);
  39 
  40   // Dashboard view-mode: the architecture overview, or one file's writeup.
  41   type View = { kind: 'overview' } | { kind: 'file'; fileId: string };
  42   const [view, setView] = useState<View>({ kind: 'overview' });
  43 
  44   // Toast for PR-create feedback.
  45   const [toast, setToast] = useState<{
  46     kind: 'success' | 'error';
  47     message: string;
  48     href?: string;
  49   } | null>(null);
  50 
  51   // Auto-dismiss toasts.
  52   useEffect(() => {
  53     if (!toast) return;
  54     const t = setTimeout(() => setToast(null), 8000);
  55     return () => clearTimeout(t);
  56   }, [toast]);
  57 
  58   // Poll for repo detail. Stops polling when both status and docsStatus
  59   // are in terminal states.
  60   useEffect(() => {
  61     if (!repositoryId) return;
  62     let cancelled = false;
  63     let timer: ReturnType<typeof setTimeout> | null = null;
  64 
  65     const tick = async () => {
  66       try {
  67         const next = await api.getRepositoryDetail({ repositoryId });
  68         if (cancelled) return;
  69         setDetail(next);
  70         setPollError(null);
  71 
  72         const ingestTerminal =
  73           next.status === 'completed' || next.status === 'failed';
  74         const docsTerminal =
  75           next.docsStatus === 'completed' || next.docsStatus === 'failed';
  76 
  77         if (ingestTerminal && docsTerminal) return; // stop polling
  78         timer = setTimeout(tick, POLL_INTERVAL_MS);
  79       } catch (err: unknown) {
  80         if (cancelled) return;
  81         const message = err instanceof Error ? err.message : String(err);
  82         setPollError(message);
  83         timer = setTimeout(tick, POLL_INTERVAL_MS);
  84       }
  85     };
  86     tick();
  87 
  88     return () => {
  89       cancelled = true;
  90       if (timer) clearTimeout(timer);
  91     };
  92   }, [repositoryId]);
  93 
  94   // Auto-trigger generateBible once ingestion completes, if the home
  95   // page asked for it. Strips the query param after firing so a manual
  96   // page reload doesn't re-fire.
  97   useEffect(() => {
  98     if (!detail || autogenerateConsumed) return;
  99     if (!autogenerateRequested) return;
 100     if (detail.status !== 'completed') return;
 101     if (detail.docsStatus !== 'idle') return;
 102     setAutogenerateConsumed(true);
 103     api
 104       .generateBible({ repositoryId })
 105       .catch((err) => {
 106         console.error('generateBible failed', err);
 107         setToast({
 108           kind: 'error',
 109           message:
 110             err instanceof Error
 111               ? err.message
 112               : 'Failed to start documentation generation.',
 113         });
 114       })
 115       .finally(() => {
 116         // Strip ?autogenerate=1 from the URL.
 117         navigate(`/repos/${repositoryId}`, { replace: true });
 118       });
 119   }, [
 120     detail,
 121     autogenerateRequested,
 122     autogenerateConsumed,
 123     repositoryId,
 124     navigate,
 125   ]);
 126 
 127   if (!match) return null;
 128   if (!detail && !pollError) {
 129     return <FullScreenStatus title="Loading…" subtitle={null} />;
 130   }
 131   if (!detail && pollError) {
 132     return (
 133       <FullScreenStatus
 134         title="Could not load repository"
 135         subtitle={pollError}
 136         showHome
 137       />
 138     );
 139   }
 140   if (!detail) return null;
 141 
 142   // Routing decisions per current state.
 143   if (detail.status === 'failed') {
 144     return (
 145       <FullScreenStatus
 146         title="Ingestion failed"
 147         subtitle={`${detail.repoName} could not be ingested. Check the method logs for details.`}
 148         showHome
 149       />
 150     );
 151   }
 152   if (detail.status === 'processing') {
 153     return (
 154       <FullScreenStatus
 155         title={`Ingesting ${detail.repoName}…`}
 156         subtitle="Fetching file tree, chunking source, generating embeddings. Usually under a minute for small repos, a few minutes for large ones."
 157       />
 158     );
 159   }
 160   if (detail.docsStatus === 'generating' || detail.docsStatus === 'idle') {
 161     const filesShown = detail.docsStatus === 'generating' ? detail.files.length : 0;
 162     return (
 163       <FullScreenStatus
 164         title={
 165           detail.docsStatus === 'generating'
