 192   }
 193   if (detail.docsStatus === 'failed') {
 194     return (
 195       <FullScreenStatus
 196         title="Documentation generation failed"
 197         subtitle={`Generation crashed midway. Check method logs for details. You can try again.`}
 198         showHome
