 97           style={{
 98             margin: '12px 0 0',
 99             whiteSpace: 'pre-wrap',
100             color: 'var(--text-muted)',
101             fontSize: 11,
102           }}
103         >
104           {chart}
105         </pre>
106       </div>
107     );
108   }
109 
110   return (
111     <div
112       ref={ref}
113       className="mermaid-block"
114       style={{
115         margin: '24px 0',
116         padding: 24,
117         background: 'var(--bg-pane)',
