132       <ReactMarkdown
133         remarkPlugins={[remarkGfm]}
134         rehypePlugins={[rehypeHighlight]}
135         components={{
136           // Custom code component to detect ```mermaid fences.
137           code(props) {
138             const { className, children, ...rest } = props;
139             const match = /language-(\w+)/.exec(className ?? '');
140             const lang = match?.[1];
141             const text = String(children ?? '').replace(/\n$/, '');
142 
143             // Mermaid fence -> render to SVG.
144             if (lang === 'mermaid') {
145               return <MermaidBlock chart={text} />;
146             }
147 
148             // Inline code (no language class).
149             if (!lang) {
150               return (
151                 <code className={className} {...rest}>
152                   {children}
153                 </code>
154               );
155             }
156 
157             // Fenced code with a language — let rehype-highlight do its thing.
158             return (
159               <code className={className} {...rest}>
160                 {children}
161               </code>
162             );
163           },
164         }}
165       >
166         {content}
167       </ReactMarkdown>
168       <MarkdownStyles />
169     </div>
