messages.content:
  1 /*
  2  * Codebase Bible — design tokens.
  3  * Dark, IDE-inspired. Single accent (mint/cyan). Inter for prose,
  4  * JetBrains Mono for code. Sharp 1px lines, no rounded corners on chrome.
  5  */
  6 
  7 :root {
  8   /* Surfaces */
  9   --bg: #0a0b0d;
 10   --bg-elevated: #111316;
 11   --bg-pane: #0d0f12;
 12   --bg-hover: #1a1d22;
 13   --bg-active: #232830;
 14 
 15   /* Borders */
 16   --border: #1f242b;
 17   --border-strong: #2c333d;
 18 
 19   /* Text */
 20   --text: #e8eaed;
 21   --text-secondary: #9aa0a6;
 22   --text-muted: #5f6368;
 23 
 24   /* Accent */
 25   --accent: #00d4a4;
 26   --accent-dim: #00aa84;
 27   --accent-fade: rgba(0, 212, 164, 0.1);
 28 
 29   /* States */
 30   --status-processing: #f59e0b;
 31   --status-completed: #00d4a4;
 32   --status-failed: #ef4444;
 33   --status-idle: #6b7280;
 34 
 35   /* Typography */
 36   --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
 37   --font-mono: 'JetBrains Mono', ui-monospace, 'SF Mono', Menlo, monospace;
 38 
 39   /* Spacing scale */
 40   --sp-1: 4px;
 41   --sp-2: 8px;
 42   --sp-3: 12px;
 43   --sp-4: 16px;
 44   --sp-5: 24px;
 45   --sp-6: 32px;
 46   --sp-7: 48px;
 47   --sp-8: 64px;
 48 }
 49 
 50 * {
 51   box-sizing: border-box;
 52 }
 53 
 54 html,
 55 body,
 56 #root {
 57   height: 100%;
 58   margin: 0;
 59   padding: 0;
 60 }
 61 
 62 body {
 63   background: var(--bg);
 64   color: var(--text);
 65   font-family: var(--font-sans);
 66   font-size: 14px;
 67   line-height: 1.55;
 68   -webkit-font-smoothing: antialiased;
 69   -moz-osx-font-smoothing: grayscale;
 70 }
 71 
 72 /* Selection */
 73 ::selection {
 74   background: var(--accent-fade);
 75   color: var(--text);
 76 }
 77 
 78 /* Scrollbars */
 79 ::-webkit-scrollbar {
 80   width: 10px;
 81   height: 10px;
 82 }
 83 ::-webkit-scrollbar-track {
 84   background: transparent;
 85 }
 86 ::-webkit-scrollbar-thumb {
 87   background: var(--border);
 88   border-radius: 5px;
 89 }
 90 ::-webkit-scrollbar-thumb:hover {
 91   background: var(--border-strong);
 92 }
 93 
 94 /* ───────── Buttons ───────── */
 95 
 96 button {
 97   font-family: inherit;
 98   font-size: inherit;
 99 }
100 
101 .btn {
102   display: inline-flex;
103   align-items: center;
104   justify-content: center;
105   gap: var(--sp-2);
106   padding: 10px 16px;
107   border: 1px solid var(--border);
108   background: var(--bg-elevated);
109   color: var(--text);
110   font-family: var(--font-sans);
111   font-size: 13px;
112   font-weight: 500;
113   cursor: pointer;
114   transition: background 120ms, border-color 120ms;
115   white-space: nowrap;
116 }
117 .btn:hover:not(:disabled) {
118   background: var(--bg-hover);
119   border-color: var(--border-strong);
120 }
121 .btn:disabled {
122   opacity: 0.4;
123   cursor: not-allowed;
124 }
125 .btn-primary {
126   background: var(--accent);
127   border-color: var(--accent);
128   color: #0a0b0d;
129   font-weight: 600;
130 }
131 .btn-primary:hover:not(:disabled) {
132   background: var(--accent-dim);
133   border-color: var(--accent-dim);
134 }
135 .btn-ghost {
136   background: transparent;
137   border-color: transparent;
138 }
139 .btn-ghost:hover:not(:disabled) {
140   background: var(--bg-hover);
141 }
142 
143 /* ───────── Inputs ───────── */
144 
145 .input {
146   width: 100%;
147   padding: 12px 16px;
148   background: var(--bg-elevated);
149   border: 1px solid var(--border);
150   color: var(--text);
151   font-family: var(--font-mono);
152   font-size: 14px;
153   transition: border-color 120ms;
154   outline: none;
155 }
156 .input::placeholder {
157   color: var(--text-muted);
158 }
159 .input:focus {
160   border-color: var(--accent);
161 }
162 
163 /* ───────── Status pills ───────── */
164 
165 .status-pill {
166   display: inline-flex;
167   align-items: center;
168   gap: var(--sp-2);
169   padding: 3px 10px;
170   border: 1px solid var(--border);
171   background: var(--bg-elevated);
172   font-family: var(--font-mono);
173   font-size: 11px;
174   font-weight: 500;
175   text-transform: uppercase;
176   letter-spacing: 0.04em;
177   color: var(--text-secondary);
178 }
179 .status-pill::before {
180   content: '';
181   width: 6px;
182   height: 6px;
183   border-radius: 50%;
184   background: var(--status-idle);
185 }
186 .status-pill.is-processing::before,
187 .status-pill.is-generating::before {
188   background: var(--status-processing);
189   animation: pulse 1.4s ease-in-out infinite;
190 }
191 .status-pill.is-completed::before {
192   background: var(--status-completed);
193 }
194 .status-pill.is-failed::before {
195   background: var(--status-failed);
196 }
197 
198 @keyframes pulse {
199   0%,
200   100% {
201     opacity: 1;
202   }
203   50% {
204     opacity: 0.4;
205   }
206 }
207 
208 /* ───────── Spinners ───────── */
209 
210 .spinner {
211   width: 14px;
212   height: 14px;
213   border: 2px solid var(--border-strong);
214   border-top-color: var(--accent);
215   border-radius: 50%;
216   animation: spin 0.7s linear infinite;
217 }
218 
219 @keyframes spin {
220   to {
221     transform: rotate(360deg);
222   }
223 }
224 
225 /* ───────── Toast ───────── */
226 
227 .toast {
228   position: fixed;
229   bottom: 24px;
230   right: 24px;
231   max-width: 420px;
232   padding: 16px 20px;
233   background: var(--bg-elevated);
234   border: 1px solid var(--border-strong);
235   font-size: 13px;
236   line-height: 1.5;
237   z-index: 1000;
238   animation: slideIn 200ms ease-out;
239 }
240 .toast.is-error {
241   border-left: 3px solid var(--status-failed);
242 }
243 .toast.is-success {
244   border-left: 3px solid var(--status-completed);
245 }
246 @keyframes slideIn {
247   from {
248     transform: translateX(20px);
249     opacity: 0;
250   }
251   to {
252     transform: translateX(0);
253     opacity: 1;
254   }
255 }
256 
257 /* ───────── Highlight.js theme override (atom-one-dark-ish) ───────── */
258 
259 .hljs {
260   background: var(--bg-pane);
261   color: #d4d4d4;
262 }
263 .hljs-comment,
264 .hljs-quote {
265   color: #6b7280;
266   font-style: italic;
267 }
268 .hljs-keyword,
269 .hljs-selector-tag,
270 .hljs-built_in,
271 .hljs-name,
272 .hljs-tag {
273   color: #c678dd;
274 }
275 .hljs-string,
276 .hljs-title,
277 .hljs-section,
278 .hljs-attribute,
279 .hljs-literal,
280 .hljs-template-tag,
281 .hljs-template-variable,
282 .hljs-type,
283 .hljs-addition {
284   color: #98c379;
285 }
286 .hljs-number,
287 .hljs-symbol,
288 .hljs-bullet,
289 .hljs-meta,
290 .hljs-link {
291   color: #d19a66;
292 }
293 .hljs-variable,
294 .hljs-regexp {
295   color: #e06c75;
296 }
297 .hljs-doctag,
298 .hljs-strong {
299   font-weight: 700;
300 }
301 .hljs-emphasis {
302   font-style: italic;
303 }
304 .hljs-function .hljs-title,
305 .hljs-title.function_ {
306   color: #61afef;
307 }
308 .hljs-params {
309   color: #d4d4d4;
310 }
311

 1 /**
 2  * Typed RPC client for the backend methods. The frontend uses the
 3  * camelCase export names, NOT the kebab-case manifest IDs.
 4  */
 5 import { createClient } from '@mindstudio-ai/interface';
 6 
 7 // ── Backend response shapes (kept in sync with method return types) ──
 8 
 9 export interface RepoSummary {
10   id: string;
11   githubUrl: string;
12   repoName: string;
13   status: string;
14   docsStatus: string;
15   lastScannedAt: number | null;
16   fileCount: number;
17   hasOverview: boolean;
18   documentedFileCount: number;
19   updatedAt: number;
20 }
21 
22 export interface FileSummary {
23   id: string;
24   filePath: string;
25   language: string;
26   hasDoc: boolean;
27 }
28 
29 export interface OverviewDoc {
30   id: string;
31   markdownContent: string;
32   createdAt: number;
33 }
34 
35 export interface FileDoc {
36   id: string;
37   fileId: string;
38   markdownContent: string;
39   createdAt: number;
40 }
41 
42 export interface RepositoryDetail {
43   id: string;
44   githubUrl: string;
45   repoName: string;
46   status: string;
47   docsStatus: string;
48   lastScannedAt: number | null;
49   files: FileSummary[];
50   overview: OverviewDoc | null;
51   fileDocsByFileId: Record<string, FileDoc>;
52 }
53 
54 interface ApiContract {
55   ingestRepository(input: { githubUrl: string }): Promise<{
56     repositoryId: string;
57     repoName: string;
58     defaultBranch: string;
59     status: 'processing';
60   }>;
61 
62   generateBible(input: { repositoryId: string }): Promise<{
63     repositoryId: string;
64     repoName: string;
65     docsStatus: 'generating';
66   }>;
67 
68   listRepositories(): Promise<{ repositories: RepoSummary[] }>;
69 
70   getRepositoryDetail(input: { repositoryId: string }): Promise<RepositoryDetail>;
71 
72   openDocumentationPR(input: { repositoryId: string }): Promise<{
73     prUrl: string;
74     prNumber: number;
75     branch: string;
76     fileCount: number;
77   }>;
78 }
79 
80 export const api = createClient<ApiContract>();
81

  1 import { useEffect, useState, type FormEvent } from 'react';
  2 import { useLocation } from 'wouter';
  3 import { api, type RepoSummary } from '../api';
  4 
  5 /**
  6  * Home page. Two areas:
  7  *   - Top hero with the URL input.
  8  *   - Below: list of every repo the system already knows about, with
  9  *     status pills and quick links into each repo's dashboard.
 10  *
 11  * Submit flow:
 12  *   1. POST ingestRepository → repositoryId returned in <500ms.
 13  *   2. Navigate immediately to /repos/<id>. The dashboard handles the
 14  *      polling + auto-trigger for generateBible. We don't block the
 15  *      home page on async work.
 16  */
 17 export default function HomePage() {
 18   const [, navigate] = useLocation();
 19   const [url, setUrl] = useState('');
 20   const [submitting, setSubmitting] = useState(false);
 21   const [error, setError] = useState<string | null>(null);
 22 
 23   const [repos, setRepos] = useState<RepoSummary[] | null>(null);
 24   const [reposLoading, setReposLoading] = useState(true);
 25 
 26   // Initial load + refresh-on-mount. We poll lightly (every 5s) so any
 27   // repo that's currently processing/generating shows live status.
 28   useEffect(() => {
 29     let cancelled = false;
 30     let timer: ReturnType<typeof setTimeout> | null = null;
 31 
 32     const tick = async () => {
 33       try {
 34         const res = await api.listRepositories();
 35         if (!cancelled) {
 36           setRepos(res.repositories);
 37           setReposLoading(false);
 38         }
 39       } catch (err) {
 40         if (!cancelled) {
 41           console.error('listRepositories failed', err);
 42           setReposLoading(false);
 43         }
 44       }
 45       if (!cancelled) {
 46         timer = setTimeout(tick, 5000);
 47       }
 48     };
 49     tick();
 50 
 51     return () => {
 52       cancelled = true;
 53       if (timer) clearTimeout(timer);
 54     };
 55   }, []);
 56 
 57   const handleSubmit = async (e: FormEvent) => {
 58     e.preventDefault();
 59     if (!url.trim() || submitting) return;
 60     setError(null);
 61     setSubmitting(true);
 62     try {
 63       const res = await api.ingestRepository({ githubUrl: url.trim() });
 64       // Hand off to the dashboard, which will poll status and auto-trigger
 65       // generateBible once ingestion completes.
 66       navigate(`/repos/${res.repositoryId}?autogenerate=1`);
 67     } catch (err: unknown) {
 68       const message = err instanceof Error ? err.message : String(err);
 69       setError(message);
 70       setSubmitting(false);
 71     }
 72   };
 73 
 74   return (
 75     <div
 76       style={{
 77         flex: 1,
 78         display: 'flex',
 79         flexDirection: 'column',
 80         alignItems: 'center',
 81         padding: '64px 24px 80px',
 82       }}
 83     >
 84       <div style={{ width: '100%', maxWidth: 720 }}>
 85         <Hero />
 86         <form onSubmit={handleSubmit} style={{ marginTop: 32 }}>
 87           <div style={{ display: 'flex', gap: 8 }}>
 88             <input
 89               type="url"
 90               required
 91               autoFocus
 92               placeholder="https://github.com/owner/repo"
 93               value={url}
 94               onChange={(e) => setUrl(e.target.value)}
 95               disabled={submitting}
 96               className="input"
 97               style={{ flex: 1 }}
 98             />
 99             <button
100               type="submit"
101               disabled={submitting || !url.trim()}
102               className="btn btn-primary"
103               style={{ minWidth: 160 }}
104             >
105               {submitting ? <Spinner /> : 'Generate Bible →'}
106             </button>
107           </div>
108           {error && (
109             <div
110               style={{
111                 marginTop: 12,
112                 padding: '10px 14px',
113                 background: 'var(--bg-elevated)',
114                 borderLeft: '3px solid var(--status-failed)',
115                 fontFamily: 'var(--font-mono)',
116                 fontSize: 12,
117                 color: 'var(--text-secondary)',
118               }}
119             >
120               {error}
121             </div>
122           )}
123         </form>
124 
125         <div
126           style={{
127             marginTop: 16,
128             fontFamily: 'var(--font-mono)',
129             fontSize: 11,
130             color: 'var(--text-muted)',
131             letterSpacing: '0.02em',
132           }}
133         >
134           Public repos work without configuration. Private repos and PR creation require a GITHUB_TOKEN secret.
135         </div>
136 
137         <div style={{ marginTop: 64 }}>
138           <SectionLabel>Repositories</SectionLabel>
139           <RepoList repos={repos} loading={reposLoading} />
140         </div>
141       </div>
142     </div>
143   );
144 }
145 
146 function Hero() {
147   return (
148     <div>
149       <div
150         style={{
151           fontFamily: 'var(--font-mono)',
152           fontSize: 11,
153           textTransform: 'uppercase',
154           letterSpacing: '0.12em',
155           color: 'var(--accent)',
156           marginBottom: 12,
157         }}
158       >
159         AI-generated onboarding docs
160       </div>
161       <h1
162         style={{
163           fontSize: 40,
164           fontWeight: 700,
165           letterSpacing: '-0.025em',
166           lineHeight: 1.1,
167           margin: 0,
168         }}
169       >
170         Read any codebase
171         <br />
172         like you wrote it.
173       </h1>
174       <p
175         style={{
176           marginTop: 16,
177           fontSize: 16,
178           color: 'var(--text-secondary)',
179           lineHeight: 1.55,
180         }}
181       >
182         Point Codebase Bible at a GitHub URL. It clones the file tree, embeds the source, and runs two AI agents over the result — a Mapper for the architecture and a Deep-Dive for every file. Open a PR with the result in one click.
183       </p>
184     </div>
185   );
186 }
187 
188 function SectionLabel({ children }: { children: React.ReactNode }) {
189   return (
190     <div
191       style={{
192         fontFamily: 'var(--font-mono)',
193         fontSize: 11,
194         textTransform: 'uppercase',
195         letterSpacing: '0.08em',
196         color: 'var(--text-muted)',
197         marginBottom: 12,
198       }}
199     >
200       {children}
201     </div>
202   );
203 }
204 
205 function RepoList({
206   repos,
207   loading,
208 }: {
209   repos: RepoSummary[] | null;
210   loading: boolean;
211 }) {
212   const [, navigate] = useLocation();
213 
214   if (loading && !repos) {
215     return (
216       <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
217         {[0, 1, 2].map((i) => (
218           <div
219             key={i}
220             style={{
221               height: 68,
222               background: 'var(--bg-elevated)',
223               border: '1px solid var(--border)',
224               opacity: 0.5,
225             }}
226           />
227         ))}
228       </div>
229     );
230   }
231 
232   if (!repos || repos.length === 0) {
233     return (
234       <div
235         style={{
236           padding: '32px 0',
237           fontFamily: 'var(--font-mono)',
238           fontSize: 12,
239           color: 'var(--text-muted)',
240           letterSpacing: '0.02em',
241         }}
242       >
243         No repositories yet. Drop a URL in the box above to start.
244       </div>
245     );
246   }
247 
248   return (
249     <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
250       {repos.map((r) => (
251         <button
252           key={r.id}
253           onClick={() => navigate(`/repos/${r.id}`)}
254           style={{
255             all: 'unset',
256             cursor: 'pointer',
257             display: 'flex',
258             alignItems: 'center',
259             justifyContent: 'space-between',
260             gap: 16,
261             padding: '14px 18px',
262             border: '1px solid var(--border)',
263             background: 'var(--bg-elevated)',
264             transition: 'background 120ms, border-color 120ms',
265           }}
266           onMouseEnter={(e) => {
267             e.currentTarget.style.background = 'var(--bg-hover)';
268             e.currentTarget.style.borderColor = 'var(--border-strong)';
269           }}
270           onMouseLeave={(e) => {
271             e.currentTarget.style.background = 'var(--bg-elevated)';
272             e.currentTarget.style.borderColor = 'var(--border)';
273           }}
274         >
275           <div style={{ minWidth: 0, flex: 1 }}>
276             <div
277               style={{
278                 fontFamily: 'var(--font-mono)',
279                 fontSize: 14,
280                 fontWeight: 600,
281                 color: 'var(--text)',
282               }}
283             >
284               {r.repoName}
285             </div>
286             <div
287               style={{
288                 marginTop: 4,
289                 fontSize: 12,
290                 color: 'var(--text-muted)',
291                 fontFamily: 'var(--font-mono)',
292               }}
293             >
294               {r.fileCount} {r.fileCount === 1 ? 'file' : 'files'} ingested
295               {r.documentedFileCount > 0
296                 ? ` · ${r.documentedFileCount} documented`
297                 : ''}
298               {r.hasOverview ? ' · architecture ready' : ''}
299             </div>
300           </div>
301           <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
302             <span className={`status-pill is-${r.status}`}>ingest {r.status}</span>
303             <span className={`status-pill is-${r.docsStatus}`}>
304               docs {r.docsStatus}
305             </span>
306           </div>
307         </button>
308       ))}
309     </div>
310   );
311 }
312 
313 function Spinner() {
314   return <span className="spinner" />;
315 }
316

   1 /**
   2  * Repository dashboard. Three states the page transitions through:
   3  *
   4  *   1. INGESTING   — `repo.status === 'processing'`. Polling.
   5  *                    On `'completed'`, if `?autogenerate=1` is in the URL
   6  *                    AND `docsStatus === 'idle'`, fire generateBible
   7  *                    automatically (then drop the query param).
   8  *
   9  *   2. GENERATING  — `repo.docsStatus === 'generating'`. Polling.
  10  *                    A skeleton tree + progress message.
  11  *
  12  *   3. READY       — both completed. Full dashboard: file tree (left),
  13  *                    markdown reader (right), "Push to GitHub" (top-right).
  14  *
  15  * Failures (`status === 'failed'` or `docsStatus === 'failed'`) surface
  16  * inline with a short message and a back-to-home link.
  17  */
  18 
  19 import { useEffect, useMemo, useState } from 'react';
  20 import { useLocation, useRoute, Link } from 'wouter';
  21 import { api, type RepositoryDetail, type FileSummary } from '../api';
