 47 /**
 48  * Mermaid block — receives the source text inside a ```mermaid fence,
 49  * renders it to SVG via `mermaid.render`, and inserts the SVG into the
 50  * DOM. Re-renders when the content changes (different doc selected).
 51  */
 52 function MermaidBlock({ chart }: { chart: string }) {
 53   const ref = useRef<HTMLDivElement>(null);
 54   const [error, setError] = useState<string | null>(null);
 55   const idRef = useRef(`mermaid-${Math.random().toString(36).slice(2, 11)}`);
 56 
 57   useEffect(() => {
 58     ensureMermaid();
 59     let cancelled = false;
 60     setError(null);
 61     mermaid
 62       .render(idRef.current, chart)
 63       .then(({ svg }) => {
 64         if (!cancelled && ref.current) {
 65           ref.current.innerHTML = svg;
 66         }
 67       })
 68       .catch((err) => {
 69         if (!cancelled) {
 70           setError(err?.message ?? String(err));
 71         }
 72       });
 73     return () => {
 74       cancelled = true;
 75     };
 76   }, [chart]);
 77 
 78   if (error) {
 79     return (
 80       <div
 81         style={{
 82           border: '1px solid var(--border)',
 83           borderLeft: '3px solid var(--status-failed)',
 84           padding: '16px 20px',
 85           margin: '16px 0',
 86           fontFamily: 'var(--font-mono)',
 87           fontSize: 12,
 88           color: 'var(--text-secondary)',
 89           background: 'var(--bg-pane)',
 90         }}
 91       >
 92         <div style={{ color: 'var(--status-failed)', marginBottom: 8 }}>
 93           Mermaid render error
 94         </div>
 95         <pre style={{ margin: 0, whiteSpace: 'pre-wrap' }}>{error}</pre>
 96         <pre
 97           style={{
 98             margin: '12px 0 0',
 99             whiteSpace: 'pre-wrap',
100             color: 'var(--text-muted)',
101             fontSize: 11,
102           }}
103         >
104           {chart}
105         </pre>
106       </div>
107     );
108   }
109 
110   return (
111     <div
112       ref={ref}
113       className="mermaid-block"
114       style={{
115         margin: '24px 0',
116         padding: 24,
117         background: 'var(--bg-pane)',
118         border: '1px solid var(--border)',
119         overflow: 'auto',
120       }}
121     />
122   );
123 }
